module calendar(
    input CLK,
    input RST,
    output [5:0] Hours,
    output [5:0] Mins,
    output [5:0] Secs
);

reg [5:0] sec_reg, min_reg, hour_reg;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        sec_reg <= 6'd0;
        min_reg <= 6'd0;
        hour_reg <= 6'd0;
    end
    else begin
        if (sec_reg == 6'd59) begin
            sec_reg <= 6'd0;
            if (min_reg == 6'd59) begin
                min_reg <= 6'd0;
                if (hour_reg == 6'd23) begin
                    hour_reg <= 6'd0;
                end
                else begin
                    hour_reg <= hour_reg + 6'd1;
                end
            end
            else begin
                min_reg <= min_reg + 6'd1;
            end
        end
        else begin
            sec_reg <= sec_reg + 6'd1;
        end
    end
end

assign Hours = hour_reg;
assign Mins = min_reg;
assign Secs = sec_reg;

endmodule
